import {
  BadRequestException,
  Injectable,
  NotFoundException,
} from "@nestjs/common";
import { InjectRepository } from "@nestjs/typeorm";
import { Repository, IsNull } from "typeorm";
import { Invoice } from "../../database/entities/Invoice.entity";
import { Client } from "../../database/entities/Client.entity";
import {
  CreateInvoiceDto,
  UpdateInvoiceDto,
  InvoiceFiltersDto,
  GenerateInvoicePdfDto,
} from "../dto/invoice.dto";
import { StorageProviderService } from "../../file-storage/services/storage-provider.service";
import { NotificationService } from "../../notifications/services/notification.service";
import {
  NotificationChannel,
  NotificationPriority,
  NotificationType,
} from "../../database/entities/enums/notification-types.enum";

/**
 * Invoice Service
 */
@Injectable()
export class InvoiceService {
  constructor(
    @InjectRepository(Invoice)
    private readonly invoiceRepository: Repository<Invoice>,
    @InjectRepository(Client)
    private readonly clientRepository: Repository<Client>,
    private readonly storageProviderService: StorageProviderService,
    private readonly notificationService: NotificationService,
  ) {}

  /**
   * Get all invoices with filters
   */
  async findAll(
    tenantId: string,
    filters: InvoiceFiltersDto = {},
  ): Promise<{ data: Invoice[]; total: number; page: number; limit: number }> {
    const query = this.invoiceRepository
      .createQueryBuilder("invoice")
      .where("invoice.tenantId = :tenantId AND invoice.deletedAt IS NULL", {
        tenantId,
      });

    // Filter by client
    if (filters.clientId) {
      query.andWhere("invoice.clientId = :clientId", {
        clientId: filters.clientId,
      });
    }

    // Filter by status
    if (filters.status) {
      query.andWhere("invoice.status = :status", { status: filters.status });
    }

    // Filter by date range
    if (filters.invoiceDateFrom && filters.invoiceDateTo) {
      query.andWhere(
        "invoice.invoiceDate BETWEEN :invoiceDateFrom AND :invoiceDateTo",
        {
          invoiceDateFrom: new Date(filters.invoiceDateFrom),
          invoiceDateTo: new Date(filters.invoiceDateTo),
        },
      );
    } else if (filters.invoiceDateFrom) {
      query.andWhere("invoice.invoiceDate >= :invoiceDateFrom", {
        invoiceDateFrom: new Date(filters.invoiceDateFrom),
      });
    } else if (filters.invoiceDateTo) {
      query.andWhere("invoice.invoiceDate <= :invoiceDateTo", {
        invoiceDateTo: new Date(filters.invoiceDateTo),
      });
    }

    // Search
    if (filters.search) {
      query.andWhere(
        "(invoice.invoiceNumber ILIKE :search OR " +
          "invoice.description ILIKE :search)",
        { search: `%${filters.search}%` },
      );
    }

    // Sorting
    const sortBy = filters.sortBy || "invoiceDate";
    const sortOrder = filters.sortOrder || "DESC";
    query.orderBy(`invoice.${sortBy}`, sortOrder);

    // Pagination
    const page = filters.page || 1;
    const limit = filters.limit || 20;
    const skip = (page - 1) * limit;

    query.skip(skip).take(limit);

    const [data, total] = await query.getManyAndCount();

    return {
      data,
      total,
      page,
      limit,
    };
  }

  /**
   * Get invoice by ID
   */
  async findById(tenantId: string, id: string): Promise<Invoice> {
    const invoice = await this.invoiceRepository.findOne({
      where: {
        id,
        tenantId,
        deletedAt: IsNull(),
      },
      relations: ["createdByUser"],
    });

    if (!invoice) {
      throw new NotFoundException("Рахунок не знайдено");
    }

    return invoice;
  }

  /**
   * Create new invoice
   */
  async create(
    tenantId: string,
    userId: string,
    dto: CreateInvoiceDto,
  ): Promise<Invoice> {
    // Generate invoice number
    const invoiceNumber = await this.generateInvoiceNumber(tenantId);
    const financials = this.calculateInvoiceFinancials(dto);

    const invoice = this.invoiceRepository.create({
      tenantId,
      invoiceNumber,
      clientId: dto.clientId,
      invoiceDate: new Date(dto.invoiceDate),
      dueDate: dto.dueDate ? new Date(dto.dueDate) : undefined,
      description: dto.description,
      subtotal: financials.subtotal,
      discountAmount: financials.discountAmount,
      vatAmount: financials.vatAmount,
      totalAmount: financials.totalAmount,
      internalNotes: dto.internalNotes,
      clientNotes: dto.clientNotes,
      metadata: {
        items: dto.items,
        unitType: dto.unitType,
        discountPercentage: dto.discountPercentage ?? 0,
        vatRate: dto.vatRate ?? 0,
        vatIncluded: dto.vatIncluded ?? false,
      },
      status: "draft",
      createdBy: userId,
      updatedBy: userId,
    });

    return this.invoiceRepository.save(invoice);
  }

  /**
   * Update invoice
   */
  async update(
    tenantId: string,
    id: string,
    userId: string,
    dto: UpdateInvoiceDto,
  ): Promise<Invoice> {
    const invoice = await this.findById(tenantId, id);

    Object.assign(invoice, dto, {
      updatedBy: userId,
    });

    return this.invoiceRepository.save(invoice);
  }

  /**
   * Delete invoice (soft delete)
   */
  async delete(tenantId: string, id: string, userId: string): Promise<void> {
    const invoice = await this.findById(tenantId, id);

    await this.invoiceRepository.update(
      { id, tenantId },
      {
        deletedAt: new Date(),
        updatedBy: userId,
        status: "cancelled",
      },
    );
  }

  /**
   * Send invoice
   */
  async send(tenantId: string, id: string, userId: string): Promise<Invoice> {
    const invoice = await this.findById(tenantId, id);
    const client = await this.clientRepository.findOne({
      where: {
        id: invoice.clientId,
        tenantId,
        deletedAt: IsNull(),
      },
    });

    if (!client?.email) {
      throw new BadRequestException(
        "Неможливо надіслати рахунок без email клієнта",
      );
    }

    if (!invoice.pdfUrl) {
      const generatedPdf = await this.generatePdf(tenantId, id, { userId });
      invoice.pdfUrl = generatedPdf.pdfUrl;
      invoice.pdfGeneratedAt = generatedPdf.pdfGeneratedAt;
    }

    await this.notificationService.create(tenantId, null, {
      type: NotificationType.INVOICE_CREATED,
      title: `Рахунок ${invoice.invoiceNumber}`,
      body: `Надіслано рахунок ${invoice.invoiceNumber} на ${client.email}`,
      channel: NotificationChannel.EMAIL,
      priority: NotificationPriority.HIGH,
      userEmail: client.email,
      data: {
        invoiceId: invoice.id,
        invoiceNumber: invoice.invoiceNumber,
        pdfUrl: invoice.pdfUrl,
        clientId: client.id,
        deliveryKind: "invoice",
      },
    });

    invoice.status = "sent";
    invoice.updatedBy = userId;
    invoice.metadata = {
      ...(invoice.metadata || {}),
      delivery: {
        status: "queued",
        channel: NotificationChannel.EMAIL,
        recipient: client.email,
        queuedAt: new Date().toISOString(),
      },
    };

    return this.invoiceRepository.save(invoice);
  }

  /**
   * Generate invoice PDF
   */
  async generatePdf(
    tenantId: string,
    id: string,
    dto: GenerateInvoicePdfDto,
  ): Promise<{ pdfUrl: string; pdfGeneratedAt: Date }> {
    const invoice = await this.findById(tenantId, id);
    const client = invoice.clientId
      ? await this.clientRepository.findOne({
          where: {
            id: invoice.clientId,
            tenantId,
            deletedAt: IsNull(),
          },
        })
      : null;
    const uploadResult = await this.storageProviderService.upload({
      path: `tenants/${tenantId}/invoices/${invoice.id}/`,
      fileName: `${invoice.invoiceNumber}.pdf`,
      contentType: "application/pdf",
      buffer: this.buildInvoicePdfBuffer(invoice, client),
      metadata: {
        invoiceId: invoice.id,
        invoiceNumber: invoice.invoiceNumber,
      },
      isPublic: false,
    });

    const pdfUrl = uploadResult.url;
    const pdfGeneratedAt = new Date();

    invoice.pdfUrl = pdfUrl;
    invoice.pdfGeneratedAt = pdfGeneratedAt;
    invoice.updatedBy = dto.userId;
    invoice.metadata = {
      ...(invoice.metadata || {}),
      pdf: {
        path: uploadResult.path,
        generatedAt: pdfGeneratedAt.toISOString(),
        generatedBy: dto.userId,
      },
    };

    await this.invoiceRepository.save(invoice);

    return { pdfUrl, pdfGeneratedAt };
  }

  private calculateInvoiceFinancials(dto: CreateInvoiceDto): {
    subtotal: number;
    discountAmount: number;
    vatAmount: number;
    totalAmount: number;
  } {
    const computedSubtotal =
      dto.subtotal ??
      dto.items.reduce((sum, item) => {
        const quantity = item.quantity ?? item.duration ?? 1;
        const unitPrice = item.unitPrice ?? 0;
        return sum + quantity * unitPrice;
      }, 0);
    const discountAmount = this.roundCurrency(
      computedSubtotal * ((dto.discountPercentage ?? 0) / 100),
    );
    const vatBase = this.roundCurrency(computedSubtotal - discountAmount);
    const vatRate = dto.vatRate ?? 0;
    const vatAmount = dto.vatIncluded
      ? this.roundCurrency(vatBase - vatBase / (1 + vatRate || 1))
      : this.roundCurrency(vatBase * vatRate);
    const totalAmount = dto.vatIncluded
      ? vatBase
      : this.roundCurrency(vatBase + vatAmount);

    return {
      subtotal: this.roundCurrency(computedSubtotal),
      discountAmount,
      vatAmount,
      totalAmount,
    };
  }

  private roundCurrency(value: number): number {
    return Math.round((value + Number.EPSILON) * 100) / 100;
  }

  private formatCurrencyLabel(currency?: string): string {
    const normalizedCurrency = String(currency || "").trim();

    if (
      !normalizedCurrency ||
      normalizedCurrency.toUpperCase() === "UAH" ||
      normalizedCurrency === "₴" ||
      normalizedCurrency === "грн"
    ) {
      return "грн";
    }

    return normalizedCurrency.toUpperCase();
  }

  private formatCurrencyValue(
    value: number | null | undefined,
    currency?: string,
  ): string {
    return `${this.roundCurrency(value ?? 0).toLocaleString("uk-UA", {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    })} ${this.formatCurrencyLabel(currency)}`;
  }

  private buildInvoicePdfBuffer(
    invoice: Invoice,
    client: Client | null,
  ): Buffer {
    const lines = [
      "Law Organizer Invoice",
      `Invoice Number: ${invoice.invoiceNumber}`,
      `Invoice Date: ${this.formatDate(invoice.invoiceDate)}`,
      `Due Date: ${this.formatDate(invoice.dueDate)}`,
      `Client: ${this.getClientLabel(client)}`,
      `Description: ${invoice.description || "-"}`,
      `Total: ${this.formatCurrencyValue(invoice.totalAmount, invoice.currency)}`,
      `Paid: ${this.formatCurrencyValue(invoice.paidAmount, invoice.currency)}`,
      `Outstanding: ${this.formatCurrencyValue(
        (invoice.totalAmount ?? 0) - (invoice.paidAmount ?? 0),
        invoice.currency,
      )}`,
    ];

    return this.createSimplePdf(lines.join("\n"));
  }

  private getClientLabel(client: Client | null): string {
    if (!client) {
      return "Unknown client";
    }

    return (
      client.companyName ||
      [client.lastName, client.firstName].filter(Boolean).join(" ").trim() ||
      client.email ||
      client.id
    );
  }

  private formatDate(value?: Date | null): string {
    return value ? new Date(value).toISOString().slice(0, 10) : "-";
  }

  private createSimplePdf(content: string): Buffer {
    const escapedContent = content
      .split("\n")
      .map((line) => `(${this.escapePdfText(line)}) Tj`)
      .join(" T* ");
    const stream = `BT /F1 12 Tf 50 780 Td 14 TL ${escapedContent} ET`;
    const objects = [
      "<< /Type /Catalog /Pages 2 0 R >>",
      "<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
      "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 595 842] /Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>",
      "<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
      `<< /Length ${Buffer.byteLength(stream, "utf8")} >>\nstream\n${stream}\nendstream`,
    ];
    let pdf = "%PDF-1.4\n";
    const offsets = [0];

    objects.forEach((object, index) => {
      offsets.push(Buffer.byteLength(pdf, "utf8"));
      pdf += `${index + 1} 0 obj\n${object}\nendobj\n`;
    });

    const startXref = Buffer.byteLength(pdf, "utf8");
    pdf += `xref
0 ${objects.length + 1}
0000000000 65535 f 
${offsets
  .slice(1)
  .map((offset) => `${String(offset).padStart(10, "0")} 00000 n `)
  .join("\n")}
trailer
<< /Root 1 0 R /Size ${objects.length + 1} >>
startxref
${startXref}
%%EOF`;

    return Buffer.from(pdf, "utf8");
  }

  private escapePdfText(value: string): string {
    return value
      .replace(/\\/g, "\\\\")
      .replace(/\(/g, "\\(")
      .replace(/\)/g, "\\)");
  }

  /**
   * Record payment
   */
  async recordPayment(
    tenantId: string,
    id: string,
    userId: string,
    payment: {
      amount: number;
      method: "cash" | "card" | "bank_transfer" | "wayforpay";
      reference?: string;
    },
  ): Promise<Invoice> {
    const invoice = await this.findById(tenantId, id);

    const paidAmount = invoice.paidAmount + payment.amount;
    const isFullyPaid = paidAmount >= invoice.totalAmount;

    invoice.paidAmount = paidAmount;
    invoice.paymentMethod = payment.method;
    invoice.paymentReference = payment.reference ?? "";
    invoice.paidAt = new Date();
    invoice.status = isFullyPaid ? "paid" : "partial";
    invoice.updatedBy = userId;

    return this.invoiceRepository.save(invoice);
  }

  /**
   * Generate invoice number
   */
  private async generateInvoiceNumber(tenantId: string): Promise<string> {
    const prefix = "INV";
    const date = new Date();
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, "0");

    // Get latest invoice number for this month/year
    const latest = await this.invoiceRepository
      .createQueryBuilder("invoice")
      .select("invoice.invoiceNumber")
      .where(
        "invoice.tenantId = :tenantId AND invoice.invoiceNumber LIKE :pattern",
        {
          tenantId,
          pattern: `${prefix}-${year}-${month}-%`,
        },
      )
      .orderBy("invoice.invoiceNumber", "DESC")
      .limit(1)
      .getOne();

    let number = 1;
    if (latest) {
      const parts = latest.invoiceNumber.split("-");
      number = parseInt(parts[3]) + 1;
    }

    return `${prefix}-${year}-${month}-${String(number).padStart(4, "0")}`;
  }

  /**
   * Get invoice statistics
   */
  async getStatistics(tenantId: string): Promise<{
    total: number;
    byStatus: Record<string, number>;
    totalAmount: number;
    paidAmount: number;
    outstandingAmount: number;
    overdueCount: number;
  }> {
    const now = new Date();

    const [total] = await this.invoiceRepository
      .createQueryBuilder("invoice")
      .select("COUNT(*)")
      .where("invoice.tenantId = :tenantId AND invoice.deletedAt IS NULL", {
        tenantId,
      })
      .getRawMany();

    const [byStatus] = await this.invoiceRepository
      .createQueryBuilder("invoice")
      .select("invoice.status", "COUNT(*) as count")
      .where("invoice.tenantId = :tenantId AND invoice.deletedAt IS NULL", {
        tenantId,
      })
      .groupBy("invoice.status")
      .getRawMany();

    const [totalAmount] = await this.invoiceRepository
      .createQueryBuilder("invoice")
      .select("SUM(invoice.totalAmount)")
      .where("invoice.tenantId = :tenantId AND invoice.deletedAt IS NULL", {
        tenantId,
      })
      .getRawMany();

    const [paidAmount] = await this.invoiceRepository
      .createQueryBuilder("invoice")
      .select("SUM(invoice.paidAmount)")
      .where("invoice.tenantId = :tenantId AND invoice.deletedAt IS NULL", {
        tenantId,
      })
      .getRawMany();

    const outstandingAmount =
      (totalAmount[0].sum || 0) - (paidAmount[0].sum || 0);

    const [overdueCount] = await this.invoiceRepository
      .createQueryBuilder("invoice")
      .select("COUNT(*)")
      .where(
        "invoice.tenantId = :tenantId AND " +
          "invoice.status != :paid AND " +
          "invoice.status != :cancelled AND " +
          "invoice.dueDate < :now AND " +
          "invoice.deletedAt IS NULL",
        { tenantId, paid: "paid", cancelled: now },
      )
      .getRawMany();

    return {
      total: parseInt(total[0].count),
      totalAmount: totalAmount[0].sum || 0,
      paidAmount: paidAmount[0].sum || 0,
      outstandingAmount,
      overdueCount: parseInt(overdueCount[0].count),
      byStatus: byStatus.reduce(
        (
          acc: Record<string, number>,
          row: { status: string; count: string },
        ) => {
          acc[row.status] = parseInt(row.count);
          return acc;
        },
        {} as Record<string, number>,
      ),
    };
  }
}
